mapper.select:
SELECT N.ID, N.NOTI_TYP, T.CD_NM_KO AS NOTI_TYP_NM, N.TO_ADDR, N.TO_USR_ID, N.TITLE, N.CONTENT,
       N.REF_TYP, N.REF_ID, N.EVENT_CD, N.SEND_STS, S.CD_NM_KO AS SEND_STS_NM,
       TO_CHAR(N.SENT_DT,'YYYY-MM-DD HH24:MI') AS SENT_DT, N.ERR_MSG, N.REG_ID,
       TO_CHAR(N.REG_DT,'YYYY-MM-DD HH24:MI') AS REG_DT
  FROM CM_NOTICE N
  LEFT JOIN CM_CODE T ON T.GRP_CD='NOTI_TYP' AND T.CD=N.NOTI_TYP AND T.DEL_YN='N'
  LEFT JOIN CM_CODE S ON S.GRP_CD='NOTI_STS' AND S.CD=N.SEND_STS AND S.DEL_YN='N'
 WHERE 1=1
AND N.NOTI_TYP=#{notiTyp}
AND N.SEND_STS=#{sendSts}
AND N.TO_USR_ID=#{toUsrId}
AND N.REF_TYP=#{refTyp}
AND N.REF_ID=#{refId}
 ORDER BY N.ID DESC

mapper.update:
UPDATE CM_NOTICE SET SEND_STS=#{sendSts}, ERR_MSG=#{errMsg},
       SENT_DT = CASE WHEN #{sendSts}='SENT' THEN SYSTIMESTAMP ELSE SENT_DT END
 WHERE ID=#{id}
